class Playground {
    async run(inputs) {
        const vals = inputs[0].split(',').map(s => s.trim()).filter(s => s !== "");
        const pos = parseInt(inputs[1]);

        if (vals.length === 0) return false;

        // 1. Initialize structures
        await this.mainList.init(vals);
        await this.stateMap.init([
            ["Slow Pointer", "null"],
            ["Fast Pointer", "null"],
            ["Cycle Detected", "false"]
        ]);

        // 2. Setup Cycle for visualization if pos >= 0
        let headId = this.mainList.getHeadId();
        let tailId = headId;
        let cycleTargetId = null;
        let nodes = [];

        // Traverse to find node IDs for cycle creation
        let current = headId;
        let index = 0;
        while (current !== null) {
            nodes.push(current);
            if (index === pos) cycleTargetId = current;
            tailId = current;
            current = this.mainList.getNextId(current);
            index++;
        }

        if (pos >= 0 && cycleTargetId) {
            this.log(`Creating a cycle from the last node to node at index ${pos}`);
            await this.mainList.link(tailId, cycleTargetId, "next");
            await this.await();
        }

        // 3. Algorithm: Tortoise and Hare
        let slow = headId;
        let fast = headId;

        this.mainList.createPointer("slow", slow, "#3b82f6");
        this.mainList.createPointer("fast", fast, "#ef4444");
        this.log("Initializing Slow and Fast pointers at head.");
        await this.await();

        while (fast !== null) {
            // Move slow
            slow = this.mainList.getNextId(slow);
            this.mainList.movePointer("slow", slow);
            this.stateMap.put("Slow Pointer", slow || "null");

            // Move fast once
            fast = this.mainList.getNextId(fast);
            if (fast !== null) {
                this.mainList.movePointer("fast", fast);
                this.stateMap.put("Fast Pointer", fast);
                this.log("Moving slow 1 step, fast 1 step...");
                await this.await();

                // Move fast twice
                fast = this.mainList.getNextId(fast);
                if (fast !== null) {
                    this.mainList.movePointer("fast", fast);
                    this.stateMap.put("Fast Pointer", fast);
                }
            }

            this.log("Moving fast the second step...");
            await this.await();

            if (fast === null) {
                this.log("Fast pointer reached null. No cycle detected.");
                return false;
            }

            if (slow === fast) {
                this.log("Slow and Fast pointers met! Cycle detected.");
                this.stateMap.put("Cycle Detected", "TRUE");
                this.mainList.highlightNode(slow, "#22c55e");
                await this.await();
                return true;
            }
        }

        this.log("End of list reached.");
        return false;
    }
}
